Rule.Source:
import sailpoint.object.ResourceObject;
import sailpoint.tools.Util;
  import sailpoint.object.Attributes;
  import sailpoint.object.Custom;
  import java.util.Map;
  import org.ascn.utils.GeneralUtils;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;

 String logName = "org.ascn.rule.Ascension-Rule-Customization-PeopleSoftDB";

String emplTypeAttr = "EMPL_TYPE";
String emplType = object.getAttribute(emplTypeAttr);

String prefFirstNameAttr = "PREF_FIRST_NAME";
String prefFirstName= object.getAttribute(prefFirstNameAttr);


String locationDescrAttr = "LOCATION_DESCR";
String locationDescr = object.getAttribute(locationDescrAttr);

String strEmplClass = null;
String strSetIdLocation = null;
String strPerOrg = null;
String strUsrName = null;
String strAssignedEndDate = null;
String customObj = "ASCN-PeopleSoftExclusions";
String customIlarlKey = "ILARL";

  try {
    strEmplClass = object.getStringAttribute("EMPL_CLASS");
    strSetIdLocation = object.getStringAttribute("SETID_LOCATION");
    strPerOrg = object.getStringAttribute("PER_ORG");
    strUsrName = object.getStringAttribute("EMPLID");
    strAssignedEndDate = object.getStringAttribute("ASGN_END_DT");
    List exclusionList = GeneralUtils.loadCustomList(customIlarlKey, customObj);

    if (exclusionList.contains(strEmplClass) @and Util.nullSafeCaseInsensitiveEq(customIlarlKey, strSetIdLocation) @and Util.nullSafeCaseInsensitiveEq(strPerOrg, "CWR")) {
      debug(logName,"strEmplClass"+strEmplClass);
      return null;
    }

  } catch (Exception e) {
    error(logName,"ERROR: "+e,e);
    throw new RuntimeException(logName+" ERROR: "+e,e);
  }

if (Util.nullSafeCaseInsensitiveEq(emplType, " ")) {

   object.setAttribute(emplTypeAttr, null);

}

if (Util.nullSafeCaseInsensitiveEq(locationDescr, " ")) {

   object.setAttribute(locationDescrAttr, null);

}

if (Util.nullSafeCaseInsensitiveEq(prefFirstName, " ")) {

   object.setAttribute(prefFirstNameAttr, null);

}


if(strUsrName!=null @and !strUsrName.isBlank()){
    qryOpt=new QueryOptions();
    Filter f1=Filter.or(Filter.eq("name",strUsrName),Filter.eq("employeeId",strUsrName));
    qryOpt.addFilter(f1);
    Iterator iterator = context.search(Identity.class,qryOpt);

    if(iterator != null @and iterator.hasNext()){
      Identity identity = iterator.next();
      if(identity!=null){
        boolean spaceExists = false;
        String expDt = identity.getAttribute("ctrexpDt");
        if(expDt!=null @and expDt.length()==1 @and expDt.equalsIgnoreCase(" ")){
          spaceExists = true;
        }
        //Set ctrexpDt to empty, when CWR type is having an end date and when EMP type is having/not having an end date - Added
        if(!identity.isInactive() @and !spaceExists @and (strPerOrg.equalsIgnoreCase("CWR") || strPerOrg.equalsIgnoreCase("EMP")) ){
          if( strPerOrg.equalsIgnoreCase("CWR") @and strAssignedEndDate!=null @and !strAssignedEndDate.isBlank() ){
            identity.setAttribute("ctrexpDt"," ");
          }
          if( strPerOrg.equalsIgnoreCase("EMP") ){
            identity.setAttribute("ctrexpDt"," ");
          }
          context.saveObject(identity);
          context.commitTransaction();
        }

      }
    }
  }

return object;
